      userRepo.save(makeUser({ id: 'user-3', name: 'Charlie' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 200 }));
      orderRepo.save(makeOrder({ id: 'order-3', userId: 'user-2', total: 50 }));

