      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-2', total: 200 }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(1);
      expect(analytics.totalSpent).toBe(100);
